// Remove payload_bruto_json de todas as linhas
// Junta tudo em uma única variável chamada history
// Saída: 1 item apenas

const inputItems = $input.all();

function removePayloadBrutoJsonDeep(value) {
  if (Array.isArray(value)) {
    return value.map(removePayloadBrutoJsonDeep);
  }

  if (value && typeof value === 'object') {
    const cleaned = {};

    for (const [key, val] of Object.entries(value)) {
      if (key === 'payload_bruto_json') continue;

      cleaned[key] = removePayloadBrutoJsonDeep(val);
    }

    return cleaned;
  }

  return value;
}

// Suporta dois cenários:
// 1. Várias linhas vindo como vários items do n8n
// 2. Um único item contendo um array direto
let rows = [];

if (inputItems.length === 1 && Array.isArray(inputItems[0].json)) {
  rows = inputItems[0].json;
} else if (inputItems.length === 1 && Array.isArray(inputItems[0].json.history)) {
  rows = inputItems[0].json.history;
} else if (inputItems.length === 1 && Array.isArray(inputItems[0].json.data)) {
  rows = inputItems[0].json.data;
} else {
  rows = inputItems.map(item => item.json);
}

// Ordena cronologicamente, se tiver criado_em ou id
rows.sort((a, b) => {
  const dateA = a.criado_em ? new Date(a.criado_em).getTime() : 0;
  const dateB = b.criado_em ? new Date(b.criado_em).getTime() : 0;

  if (dateA !== dateB) return dateA - dateB;

  const idA = Number(a.id || 0);
  const idB = Number(b.id || 0);

  return idA - idB;
});

const history = rows.map(row => removePayloadBrutoJsonDeep(row));

return [
  {
    json: {
      history
    }
  }
];

/*
  ============================================================
  NODE: MONTA ENTRADA ANALISTA CRM - CHATWOOT
  ============================================================

  OBJETIVO
  ------------------------------------------------------------
  Recebe webhook do Chatwoot, incluindo macro.executed, message_created
  ou payload similar, e transforma no contrato padrão do Analista CRM:

  {
    inputs,
    message,
    chatwoot,
    memory,
    lead,
    agent_name,
    should_reply
  }

  Este node foi pensado para casos como:
  - macro executada enviando guia/material;
  - mensagem pública enviada por Convertix/Ricardo;
  - atualização operacional que precisa alimentar memória/Analista CRM;
  - payload com dados importantes em contact.custom_attributes.

  Importante:
  - Se a mensagem atual NÃO for do lead, should_reply = false.
  - Se for mensagem enviada pela Bruna/time, o Analista pode registrar estado,
    mas não deve gerar resposta automática ao cliente.
*/

// ============================================================
// 1. HELPERS
// ============================================================

function clean(value, preserveNewLines = false) {
  let text = '';

  if (value === undefined || value === null) {
    text = '';
  } else if (typeof value === 'object') {
    try {
      text = JSON.stringify(value);
    } catch (e) {
      text = '';
    }
  } else {
    text = String(value);
  }

  text = text
    .replace(/\[object Object\]/gi, '')
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, ' ')
    .replace(/\uFFFD/g, ' ')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n');

  if (preserveNewLines) {
    return text
      .split('\n')
      .map(line => line.replace(/[ \t]+/g, ' ').trim())
      .filter(Boolean)
      .join('\n')
      .trim();
  }

  return text.replace(/\s+/g, ' ').trim();
}

function norm(value) {
  return clean(value)
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase();
}

function toNumberOrNull(value) {
  if (value === undefined || value === null || String(value).trim() === '') return null;
  const n = Number(value);
  return Number.isFinite(n) ? n : null;
}

function bool(value) {
  if (value === true) return true;
  if (value === false) return false;
  if (value === 1 || value === '1') return true;
  if (value === 0 || value === '0') return false;

  const s = norm(value);
  return ['true', 'sim', 'yes', 'y'].includes(s);
}

function parseJsonIfNeeded(value) {
  if (!value) return {};
  if (typeof value === 'object' && !Array.isArray(value)) return value;

  try {
    const parsed = JSON.parse(value);
    return parsed && typeof parsed === 'object' && !Array.isArray(parsed) ? parsed : {};
  } catch (e) {
    return {};
  }
}

function pick(...values) {
  for (const value of values) {
    const v = clean(value);
    if (
      v &&
      v !== 'null' &&
      v !== 'undefined' &&
      v !== 'nao_informado' &&
      v !== 'nao_definido'
    ) {
      return v;
    }
  }

  return '';
}

function normalizePhone(value) {
  const raw = clean(value);
  if (!raw) return '';

  const only = raw.replace(/[^\d+]/g, '');

  if (only.startsWith('+')) return only;

  const digits = only.replace(/\D/g, '');
  if (!digits) return '';

  return digits.startsWith('55') ? `+${digits}` : `+55${digits}`;
}

function getLastMessage(messages) {
  if (!Array.isArray(messages) || !messages.length) return {};
  return [...messages].sort((a, b) => Number(a.created_at || a.id || 0) - Number(b.created_at || b.id || 0)).at(-1) || {};
}

function getAttachments(msg) {
  if (Array.isArray(msg?.attachments)) return msg.attachments;
  if (Array.isArray(msg?.files)) return msg.files;
  return [];
}

function getAttachmentKind(msg) {
  const first = getAttachments(msg)[0] || {};
  const fileType = String(
    first.file_type ||
    first.type ||
    first.content_type ||
    first.mime_type ||
    ''
  ).toLowerCase();

  if (fileType.includes('image')) return 'image';
  if (fileType.includes('audio')) return 'audio';
  if (fileType.includes('video')) return 'video';
  if (fileType.includes('pdf')) return 'document';
  if (fileType.includes('document')) return 'document';
  if (fileType.includes('application')) return 'document';
  if (fileType.includes('file')) return 'document';
  if (getAttachments(msg).length) return 'document';

  return '';
}

function detectRole(msg) {
  const messageType = Number(msg?.message_type);
  const privateMsg = msg?.private === true;
  const senderType = norm(msg?.sender?.type || msg?.sender_type || '');
  const senderName = norm(msg?.sender?.name || msg?.sender?.available_name || '');
  const senderId = Number(msg?.sender?.id || msg?.sender_id || 0);

  if (messageType === 0) return 'lead';
  if (messageType === 2) return 'sistema';

  if (messageType === 1) {
    const isBotOrConvertix =
      senderId === 17 ||
      senderId === 1 ||
      senderName === 'convertix' ||
      senderName === 'ricardo fiorelli';

    if (privateMsg && !isBotOrConvertix && senderType === 'user') return 'nota_humana';
    if (!isBotOrConvertix && senderType === 'user') return 'humano';
    if (privateMsg) return 'nota_interna';

    return 'bruna';
  }

  return 'sistema';
}

function roleLabel(role) {
  if (role === 'lead') return 'Lead';
  if (role === 'bruna') return 'Bruna';
  if (role === 'humano') return 'Humano AuAu';
  if (role === 'nota_humana') return 'Nota Humana';
  if (role === 'nota_interna') return 'Nota Interna';
  return 'Sistema';
}

function normalizeHealth(value) {
  const s = norm(value);

  if (['sim', 'ok', 'em dia', 'em_dia', 'true'].includes(s)) return 'sim';

  if (
    [
      'nao',
      'não',
      'nao_ok',
      'não_ok',
      'atrasado',
      'atrasada',
      'pendente',
      'vencido',
      'vencida',
      'false'
    ].includes(s)
  ) {
    return 'nao';
  }

  return 'nao_informado';
}

function normalizeCastrado(value) {
  const s = norm(value);

  if (['castrado', 'castrada', 'sim', 'true'].includes(s)) return 'castrado';
  if (['nao_castrado', 'nao castrado', 'não castrado', 'nao', 'não', 'false'].includes(s)) return 'nao_castrado';

  return 'nao_informado';
}

function normalizeSexo(value) {
  const s = norm(value);

  if (s.includes('macho')) return 'macho';
  if (s.includes('femea') || s.includes('fêmea')) return 'femea';

  return 'nao_informado';
}

function normalizePorte(value) {
  const s = norm(value);

  if (['mini', 'pequeno', 'medio', 'grande', 'gigante'].includes(s)) return s;
  if (s === 'médio') return 'medio';

  return 'nao_definido';
}

function normalizeServico(value) {
  const s = norm(value);

  if (s.includes('creche')) return 'creche';
  if (s.includes('hotel') || s.includes('hospedagem')) return 'hotel';

  return 'nao_definido';
}

function normalizeStatus(value) {
  const allowed = new Set([
    'NOVO_LEAD',
    'COLETANDO_DADOS',
    'QUALIFICANDO',
    'PRE_REPROVADO',
    'APTO_PARA_AVALIACAO',
    'AGUARDANDO_PAGAMENTO',
    'COMPROVANTE_RECEBIDO',
    'TRANSFERIDO_FLAVIA',
    'ENCERRADO_NAO_PERFIL',
    'ENCERRADO_SEM_RESPOSTA',
    'ENCERRADO'
  ]);

  const v = clean(value).toUpperCase();
  return allowed.has(v) ? v : 'NOVO_LEAD';
}

function normalizeIntencao(value) {
  const allowed = new Set([
    'INTERESSE_CRECHE',
    'INTERESSE_HOTEL',
    'PEDIU_VALOR',
    'PEDIU_LOCALIZACAO',
    'PEDIU_VISITA',
    'INFORMOU_DADOS_CAO',
    'INFORMOU_DADOS_TUTOR',
    'ACEITOU_AVALIACAO',
    'RECEBEU_PIX',
    'ENVIOU_COMPROVANTE',
    'PEDIU_HUMANO',
    'MACHO_NAO_CASTRADO',
    'RACA_POTENCIAL_DANO',
    'URGENCIA_FERIADO',
    'OBJECAO_PRECO',
    'SUMIU'
  ]);

  const v = clean(value).toUpperCase();
  return allowed.has(v) ? v : '';
}

function normalizeEvento(value) {
  const allowed = new Set([
    '',
    'FORMULARIO_RECEBIDO',
    'GUIA_ENVIADO',
    'PIX_SOLICITADO',
    'ANEXO_RECEBIDO',
    'COMPROVANTE_IDENTIFICADO',
    'REPASSE_FLAVIA',
    'FOLLOWUP_DISPARADO',
    'CONVERSA_ENCERRADA'
  ]);

  const v = clean(value).toUpperCase();
  return allowed.has(v) ? v : '';
}

function extractFromLeadSummary(summaryText, label) {
  const text = String(summaryText || '');
  const escaped = label.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const re = new RegExp(`${escaped}:\\s*([^\\n]+)`, 'i');
  const match = text.match(re);
  return clean(match?.[1] || '');
}

// ============================================================
// 2. PROCESSA ITENS
// ============================================================

const out = [];

for (const item of $input.all()) {
  const root = Array.isArray(item.json) ? item.json[0] : item.json;
  const body = root?.body || root || {};

  const currentMessage = getLastMessage(body.messages || []);
  const role = detectRole(currentMessage);

  const sender = body.meta?.sender || currentMessage.sender || {};
  const custom = sender.custom_attributes || {};
  const leadSummary = clean(custom.lead_summary || '', true);

  const labels = Array.isArray(body.labels)
    ? body.labels
    : clean(custom.bruna_labels)
      .split(',')
      .map(x => x.trim())
      .filter(Boolean);

  const phone = normalizePhone(
    sender.phone_number ||
    custom.tutor_telefone ||
    extractFromLeadSummary(leadSummary, 'Telefone')
  );

  const tutorNome = pick(
    sender.name,
    extractFromLeadSummary(leadSummary, 'Tutor')
  );

  const attachments = getAttachments(currentMessage);
  const hasAttachment = attachments.length > 0;
  const attachmentKind = getAttachmentKind(currentMessage);
  const hasText = Boolean(clean(currentMessage.content || currentMessage.processed_message_content || ''));

  const messageModality = !hasAttachment
    ? 'text_only'
    : hasText
      ? `${attachmentKind || 'document'}_with_text`
      : `${attachmentKind || 'document'}_only`;

  const content = clean(
    currentMessage.content ||
    currentMessage.processed_message_content ||
    '',
    true
  );

  const historyLine = currentMessage.id
    ? `[${currentMessage.id}] ${roleLabel(role)}: ${content || `[ANEXO ${attachmentKind || 'document'} enviado]`}`
    : '';

  const statusLead = normalizeStatus(
    custom.bruna_status_lead ||
    extractFromLeadSummary(leadSummary, 'Status')
  );

  const ultimaIntencao = normalizeIntencao(
    custom.bruna_ultima_intencao ||
    extractFromLeadSummary(leadSummary, 'Intenção')
  );

  let eventoSistema = normalizeEvento(
    custom.bruna_evento_sistema ||
    extractFromLeadSummary(leadSummary, 'Evento')
  );

  // Se o evento é macro.executed e a mensagem tem guia/material, registra guia enviado.
  const msgTextNorm = norm(content);
  const hasGuideAttachment = attachments.some(att => {
    const url = norm(att.data_url || '');
    return url.includes('guia') || url.includes('pdf');
  });

  if (
    body.event === 'macro.executed' &&
    (
      msgTextNorm.includes('guia') ||
      hasGuideAttachment
    )
  ) {
    eventoSistema = 'GUIA_ENVIADO';
  }

  const servicoInteresse = normalizeServico(
    custom.bruna_servico_interesse ||
    extractFromLeadSummary(leadSummary, 'Serviço') ||
    custom.link_rastreavel
  );

  const resumoLead = {
    tutor_nome: tutorNome,
    tutor_telefone: phone,

    cao_nome: pick(custom.bruna_nome_cao, extractFromLeadSummary(leadSummary, 'Nome do cão')),
    cao_idade_anos: pick(extractFromLeadSummary(leadSummary, 'Idade')),
    cao_raca: pick(custom.bruna_raca_cao, extractFromLeadSummary(leadSummary, 'Raça')),
    cao_porte: normalizePorte(pick(custom.bruna_porte_cao, extractFromLeadSummary(leadSummary, 'Porte'))),
    cao_sexo: normalizeSexo(pick(custom.bruna_sexo_cao, extractFromLeadSummary(leadSummary, 'Sexo'))),
    cao_castrado: normalizeCastrado(pick(custom.bruna_castrado, extractFromLeadSummary(leadSummary, 'Castrado'))),
    cao_no_cio: 'nao_informado',

    cao_vacinas_ok: normalizeHealth(extractFromLeadSummary(leadSummary, 'Vacinas')),
    cao_antipulgas_ok: normalizeHealth(extractFromLeadSummary(leadSummary, 'Antipulgas')),
    cao_vermifugacao_ok: normalizeHealth(extractFromLeadSummary(leadSummary, 'Vermifugação')),
    cao_sociavel: normalizeHealth(extractFromLeadSummary(leadSummary, 'Sociável')),
    cao_reativo: normalizeHealth(extractFromLeadSummary(leadSummary, 'Reativo')),
    possui_relatorio_veterinario: 'nao_informado',

    unidade_preferida: 'nao_definida',
    servico_interesse: servicoInteresse,

    periodo_desejado: '',
    data_desejada: '',

    comprovante_recebido: bool(custom.bruna_comprovante_recebido),
    tipo_comprovante: 'nao_informado',
    data_hora_pre_reserva: '',
    responsavel_humano: bool(custom.bruna_deve_repassar_humano) ? 'Flavia' : '',

    observacoes: pick(
      extractFromLeadSummary(leadSummary, 'Observações'),
      ''
    )
  };

  const resumoInternoRepasse = {
    repassar_para: bool(custom.bruna_deve_repassar_humano) ? 'Flavia' : '',
    motivo: '',

    tutor_nome: resumoLead.tutor_nome,
    tutor_telefone: resumoLead.tutor_telefone,
    cao_nome: resumoLead.cao_nome,
    cao_idade_anos: resumoLead.cao_idade_anos,
    cao_raca: resumoLead.cao_raca,
    cao_porte: resumoLead.cao_porte,
    cao_sexo: resumoLead.cao_sexo,
    cao_castrado: resumoLead.cao_castrado,
    cao_vacinas_ok: resumoLead.cao_vacinas_ok,
    cao_antipulgas_ok: resumoLead.cao_antipulgas_ok,
    cao_sociavel: resumoLead.cao_sociavel,
    cao_reativo: resumoLead.cao_reativo,
    unidade_preferida: resumoLead.unidade_preferida,
    servico_interesse: resumoLead.servico_interesse,
    data_hora_avaliacao: '',
    comprovante_recebido: resumoLead.comprovante_recebido,
    tipo_comprovante: resumoLead.tipo_comprovante,
    observacoes: resumoLead.observacoes
  };

  const currentMessageId = toNumberOrNull(currentMessage.id);

  const message = {
    message_modality: messageModality,
    has_text: hasText,
    has_attachment: hasAttachment,
    private: currentMessage.private === true,
    type: role === 'lead' ? 'incoming' : 'outgoing',

    content,
    content_raw: content,

    created_at: currentMessage.created_at
      ? new Date(Number(currentMessage.created_at) * 1000).toISOString()
      : '',

    historico: 'chatwoot',

    history_for_crm: historyLine,
    last_bruna_message_before_current_block: role === 'bruna' ? content : '',
    current_lead_block_text: role === 'lead' ? content : '',

    current_message_id: currentMessageId,
    first_message_id: toNumberOrNull((body.messages || [])[0]?.id),
    last_message_id: currentMessageId,

    data_url: attachments[0]?.data_url || '',
    attachment_file_type: attachments[0]?.file_type || ''
  };

  const chatwoot = {
    chat_history_uuid:
      `account:${currentMessage.account_id || 3}` +
      `-inbox:${body.inbox_id || currentMessage.inbox_id || ''}` +
      `-contact:${sender.id || body.contact_inbox?.contact_id || ''}` +
      `-conversation:${body.id || currentMessage.conversation_id || ''}` +
      `-phone:${phone}`,

    labels,

    system_event: 'MESSAGE_RECEIVED',
    account_id: currentMessage.account_id || 3,
    contact_id: sender.id || body.contact_inbox?.contact_id || null,
    conversation_id: body.id || currentMessage.conversation_id || null,
    message_id: currentMessageId,

    event: body.event || '',
    inbox_id: body.inbox_id || currentMessage.inbox_id || null
  };

  const lead = {
    sender_name: tutorNome,
    phone,
    entry_channel: `${custom.origem || ''}${custom.anuncio ? ` - ${custom.anuncio}` : ''}`.trim(),
    utms: {
      source: custom.origem || '',
      campaign: '',
      medium: '',
      content: custom.anuncio || '',
      term: ''
    },
    sender_type: 'contact'
  };

  const inputs = {
    status_lead: statusLead,
    ultima_intencao: ultimaIntencao,
    evento_sistema: eventoSistema,

    apto_para_avaliacao: 'pendente',
    motivo_pre_reprovacao: '',
    status_pagamento: statusLead === 'AGUARDANDO_PAGAMENTO' ? 'aguardando_comprovante' : 'nao_solicitado',

    comprovante_recebido: resumoLead.comprovante_recebido,
    tipo_comprovante: resumoLead.tipo_comprovante,
    arquivo_comprovante_referencia: '',
    pre_reserva_criada: false,
    data_hora_avaliacao: '',
    data_hora_pre_reserva: '',

    resumo_lead: resumoLead,

    proxima_acao: pick(
      extractFromLeadSummary(leadSummary, 'Próxima ação'),
      eventoSistema === 'GUIA_ENVIADO'
        ? 'Registrar guia enviado ao lead. Não responder automaticamente porque a mensagem atual foi enviada pela Bruna/time.'
        : 'Registrar evento atual no histórico. Não responder automaticamente se a mensagem atual não for do lead.'
    ),

    deve_repassar_humano: bool(custom.bruna_deve_repassar_humano),
    motivo_repasse: '',
    deve_enviar_guia: false,
    deve_solicitar_pagamento: false,
    deve_consultar_agenda: false,
    deve_criar_pre_reserva: false,
    deve_encerrar_conversa: false,

    resumo_interno_repasse: resumoInternoRepasse,

    diagnostico_crm: {
      ultima_mensagem_relevante_lead: role === 'lead' ? content : '',
      ultima_mensagem_relevante_bruna: role === 'bruna' ? content : '',
      estado_reconstruido_com_base_em: 'webhook_chatwoot_custom_attributes_e_mensagem_atual',
      alerta_conflito: false,
      descricao_conflito: '',
      baixa_confianca: false,
      campos_com_baixa_confianca: '',
      humano_assumiu: labels.includes('01-humano-assumiu'),
      lead_pesquisando_futuro: false,
      lead_pediu_preco_ou_info_apos_pix: false
    }
  };

  const memory = {
    lead_id: null,
    status_lead_anterior: statusLead,
    ultima_intencao_anterior: ultimaIntencao,
    evento_sistema_anterior: eventoSistema,
    chat_history_uuid: chatwoot.chat_history_uuid,
    contador_followup: 0,
    tipo_ultimo_followup: '',
    ultimo_followup_em: '',
    last_processed_message_id: currentMessageId
  };

  out.push({
    json: {
      inputs,
      message,
      chatwoot,
      memory,
      lead,
      agent_name: 'Bruna',

      // Se a mensagem atual não veio do lead, não deve gerar resposta automática.
      should_reply: role === 'lead' && body.can_reply === true,

      // prepara_entrada_analista_debug: {
      //   ok: true,
      //   source_node: 'MONTA ENTRADA ANALISTA CRM - CHATWOOT',
      //   event: body.event || '',
      //   role_detectado: role,
      //   message_id: currentMessageId,
      //   has_attachment: hasAttachment,
      //   attachment_kind: attachmentKind,
      //   evento_sistema_detectado: eventoSistema,
      //   should_reply: role === 'lead' && body.can_reply === true
      // }
    }
  });
}

return out;

